import os
import json
from pathlib import Path


def process_data(source):
    raw = Path(source).read_text()
    return json.loads(raw)

def validate_email(email):
    """Validate an email address."""
    if "@" not in email:
        return False
    local, domain = email.split("@", 1)
    if len(local) < 1:
        return False
    return "." in domain
